import React, { useState, useEffect } from 'react';
import axios from 'axios';
import Navbar from '../components/Navbar';
import './Landing.css';

export default function Landing() {

  // 🔹 state for filters
  const [fuel, setFuel] = useState('');
  const [transmission, setTransmission] = useState('');
  const [type, setType] = useState('');
  const [maxPrice, setMaxPrice] = useState(3000);

  // 🔹 cars data
  const [cars, setCars] = useState([]);

  // 🔹 fetch cars function
  const fetchCars = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/cars', {
        params: {
          fuel,
          transmission,
          type,
          maxPrice
        }
      });

      console.log("Cars:", res.data);
      setCars(res.data);

    } catch (err) {
      console.error(err);
    }
  };

  // 🔹 load all cars on first render
  useEffect(() => {
    fetchCars();
  }, []);

  return (
    <div className="landing-root">
      <Navbar />

      <div className="landing-hero">
        <div className="hero-text">
          <span className="hero-tag">🚗 Rent Near You</span>
          <h1>Find Your Perfect <span>Ride</span></h1>
          <p>Transparent pricing · Zero deposit · Instant pickup</p>
        </div>
      </div>

      {/* 🔹 SEARCH PANEL */}
      <div className="search-panel">
        <div className="search-panel-inner filter-grid">

          {/* 🔹 Fuel */}
          <div className="filter-section">
            <label>Fuel</label>
            <div className="chip-row">
              <button onClick={() => setFuel("Petrol")} className="chip">Petrol</button>
              <button onClick={() => setFuel("Diesel")} className="chip">Diesel</button>
            </div>
          </div>

          {/* 🔹 Transmission */}
          <div className="filter-section">
            <label>Transmission</label>
            <div className="chip-row">
              <button onClick={() => setTransmission("Auto")} className="chip">Auto</button>
              <button onClick={() => setTransmission("Manual")} className="chip">Manual</button>
            </div>
          </div>

          {/* 🔹 Type */}
          <div className="filter-section">
            <label>Body Type</label>
            <div className="chip-row">
              <button onClick={() => setType("SUV")} className="chip">SUV</button>
              <button onClick={() => setType("Hatchback")} className="chip">Hatchback</button>
              <button onClick={() => setType("Sedan")} className="chip">Sedan</button>
            </div>
          </div>

          {/* 🔹 Price */}
          <div className="filter-section full-width">
            <label>Max Price: ₹{maxPrice}</label>
            <input
              type="range"
              min={500}
              max={10000}
              value={maxPrice}
              onChange={(e) => setMaxPrice(e.target.value)}
              className="price-slider"
            />
          </div>

          {/* 🔥 Search Button */}
          <button className="btn-search" onClick={fetchCars}>
            🔍 Search
          </button>

        </div>
      </div>

      {/* 🔥 CAR LIST */}
      <div style={{ padding: "20px" }}>
        <h2>Available Cars</h2>

        {cars.length === 0 ? (
          <p>No cars found</p>
        ) : (
          <div style={{ display: "flex", gap: "20px", flexWrap: "wrap" }}>
            {cars.map((car) => (
              <div key={car._id} style={{ border: "1px solid #ccc", padding: "10px", width: "200px" }}>
                <h3>{car.name}</h3>
                <p>Fuel: {car.fuel}</p>
                <p>Type: {car.type}</p>
                <p>₹{car.pricePerDay}/day</p>
              </div>
            ))}
          </div>
        )}
      </div>

    </div>
  );
}
